import sys
import argparse
from kafka import KafkaAdminClient
from kafka.admin import NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import TopicAlreadyExistsError, UnknownTopicOrPartitionError

def create_topic(admin_client, topic_name, num_partitions, replication_factor, configs):
    try:
        topic = NewTopic(
            name=topic_name,
            num_partitions=num_partitions,
            replication_factor=replication_factor,
            topic_configs=configs
        )
        admin_client.create_topics([topic], validate_only=False)
        print(f"Topic '{topic_name}' created successfully")
    except TopicAlreadyExistsError:
        print(f"Topic '{topic_name}' already exists")
    except Exception as e:
        print(f"Error creating topic '{topic_name}': {e}")

def list_topics(admin_client):
    try:
        topics = admin_client.list_topics()
        print("Topics:")
        for topic in topics:
            print(f"  {topic}")
    except Exception as e:
        print(f"Error listing topics: {e}")

def describe_topic(admin_client, topic_name):
    try:
        topic_configs = admin_client.describe_configs([
            ConfigResource(ConfigResourceType.TOPIC, topic_name)
        ])
        print(f"Configs for topic '{topic_name}':")
        for config_resource, config in topic_configs.items():
            for key, value in config.items():
                print(f"  {key}: {value}")
    except UnknownTopicOrPartitionError:
        print(f"Topic '{topic_name}' not found")
    except Exception as e:
        print(f"Error describing topic '{topic_name}': {e}")

def delete_topic(admin_client, topic_name):
    try:
        admin_client.delete_topics([topic_name])
        print(f"Topic '{topic_name}' deletion initiated")
    except Exception as e:
        print(f"Error deleting topic '{topic_name}': {e}")

def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration')
    parser.add_argument('--bootstrap-servers', required=True, help='Kafka bootstrap servers')
    parser.add_argument('--action', choices=['create', 'list', 'describe', 'delete'], required=True, help='Action to perform')
    parser.add_argument('--topic', help='Topic name')
    parser.add_argument('--partitions', type=int, help='Number of partitions')
    parser.add_argument('--replication-factor', type=int, help='Replication factor')
    parser.add_argument('--config', nargs='*', help='Topic configurations in key=value format')
    
    args = parser.parse_args()
    
    admin_client = KafkaAdminClient(bootstrap_servers=args.bootstrap_servers)
    
    configs = {}
    if args.config:
        for config in args.config:
            key, value = config.split('=', 1)
            configs[key] = value
    
    if args.action == 'create':
        if not args.topic or not args.partitions or not args.replication_factor:
            print("Error: --topic, --partitions, and --replication-factor are required for create action")
            sys.exit(1)
        create_topic(admin_client, args.topic, args.partitions, args.replication_factor, configs)
    
    elif args.action == 'list':
        list_topics(admin_client)
    
    elif args.action == 'describe':
        if not args.topic:
            print("Error: --topic is required for describe action")
            sys.exit(1)
        describe_topic(admin_client, args.topic)
    
    elif args.action == 'delete':
        if not args.topic:
            print("Error: --topic is required for delete action")
            sys.exit(1)
        delete_topic(admin_client, args.topic)

if __name__ == '__main__':
    main()